#Alignerimport numpy as npdef align_xy(sample_spectra, gcms_df):    import numpy as np    X = []    sample_ids = []    group_labels = []    # Normalize GCMS index    gcms_df.index = gcms_df.index.str.strip()    # Extract and remove class column if present    has_class = "Class" in gcms_df.columns    if has_class:        class_series = gcms_df["Class"].copy()        gcms_df = gcms_df.drop(columns=["Class"])    # Normalize sample IDs from spectra    for raw_id, spectra in sample_spectra.items():        sample_id = raw_id.strip()        spectral_data = np.array([spectrum.spectral_data for spectrum in spectra])        X.extend(spectral_data)        sample_ids.extend([sample_id] * len(spectral_data))        group = sample_id.split("-")[0]        group_labels.extend([group] * len(spectral_data))    X = np.vstack(X)    common_ids = set(sample_ids).intersection(set(gcms_df.index))    unmatched_ids = set(sample_ids).symmetric_difference(set(gcms_df.index))    if unmatched_ids:        print(f"Could not match data for these IDs: {unmatched_ids}")    filtered_X = []    filtered_sample_ids = []    filtered_group_labels = []    for i, sample_id in enumerate(sample_ids):        if sample_id in common_ids:            filtered_X.append(X[i])            filtered_sample_ids.append(sample_id)            filtered_group_labels.append(group_labels[i])    filtered_X = np.vstack(filtered_X)    filtered_Y = gcms_df.loc[filtered_sample_ids]    # Align class labels if present    if has_class:        class_labels = class_series.loc[filtered_sample_ids].tolist()    else:        class_labels = None    return filtered_X, filtered_Y, filtered_sample_ids, filtered_group_labels, class_labels, unmatched_idsdef align_group_xy(group_spectra, gcms_df):    """    Align X (group-averaged spectra) and Y (group-averaged GC-MS) based on group IDs.    Parameters:        group_spectra (dict): Keys are group IDs, values are ramanspy.Spectrum objects.        gcms_df (pd.DataFrame): GC-MS targets with group IDs as index.    Returns:        filtered_X (np.ndarray)        filtered_Y (pd.DataFrame)        filtered_group_ids (list)        class_labels (list or None)        unmatched_ids (set)    """    import numpy as np    # Normalize GCMS index    gcms_df.index = gcms_df.index.astype(str).str.strip()    # Handle optional 'Class' column    has_class = "Class" in gcms_df.columns    if has_class:        class_series = gcms_df["Class"].copy()        gcms_df = gcms_df.drop(columns=["Class"])    X = []    group_ids = []    # Match keys    input_ids = set(group_spectra.keys())    target_ids = set(gcms_df.index)    common_ids = input_ids.intersection(target_ids)    unmatched_ids = input_ids.symmetric_difference(target_ids)    if unmatched_ids:        print(f"⚠️ Could not match GC-MS data for these group IDs: {unmatched_ids}")    for group_id in sorted(common_ids):        spectrum = group_spectra[group_id]        X.append(spectrum.spectral_data)        group_ids.append(group_id)    if not X:        raise ValueError("No overlapping group IDs between spectra and GC-MS table.")    filtered_X = np.vstack(X)    filtered_Y = gcms_df.loc[group_ids]    # Handle class labels if available    class_labels = class_series.loc[group_ids].tolist() if has_class else None    return filtered_X, filtered_Y, group_ids, class_labels, unmatched_ids